() => {
  const [fruit, setFruit] = React.useState('apple');
  return (<Stack gap={1}>
    <Select value={fruit} onValueChange={(next) => setFruit(String(next))} placeholder='Choose a fruit'>
      <Select.Option value='apple'>Apple</Select.Option>
      <Select.Option value='banana'>Banana</Select.Option>
      <Select.Option value='cherry'>Cherry</Select.Option>
    </Select>
    <Typography>Selected: {fruit}</Typography>
  </Stack>);
}

() => {
  const useStore = Valet.createFormStore({ size: 'md' });
  return (<FormControl useStore={useStore} onSubmitValues={(values) => void values}>
    <Stack gap={1}>
      <Select name='size' placeholder='Pick a size'>
        <Select.Option value='sm'>Small</Select.Option>
        <Select.Option value='md'>Medium</Select.Option>
        <Select.Option value='lg'>Large</Select.Option>
      </Select>
      <Button type='submit'>Save</Button>
    </Stack>
  </FormControl>);
}

() => {
  const [picked, setPicked] = React.useState<(string | number)[]>(['react']);
  const options = ['react', 'vue', 'svelte', 'angular', 'solid', 'qwik', 'preact'];
  return (<Stack gap={1}>
    <Select multiple value={picked} onValueChange={(next) => setPicked(Array.isArray(next) ? next : [next])} placeholder='Pick frameworks'>
      {options.map((opt) => (<Select.Option key={opt} value={opt}>{opt}</Select.Option>))}
    </Select>
    <Typography>Picked {picked.length} of {options.length}</Typography>
  </Stack>);
}
